-- Example: MVCC snapshot read vs locking read
START TRANSACTION;
SELECT * FROM orders WHERE user_id = 1;      -- snapshot read (MVCC)
SELECT * FROM orders WHERE user_id = 1 FOR UPDATE; -- locking read (current)

-- SQL: N+1 problem → fix with JOIN
-- BAD: 1 query for users + N queries for orders
SELECT * FROM users;  -- then for each user:
SELECT * FROM orders WHERE user_id = ?;

-- GOOD: single join
SELECT u.*, o.*
FROM users u
LEFT JOIN orders o ON u.id = o.user_id
WHERE u.status = 'ACTIVE';

-- JPA FETCH JOIN
@Query("SELECT u FROM User u JOIN FETCH u.orders WHERE u.active = true")
List<User> findActiveWithOrders();

