-- Common deadlock pattern: concurrent updates in opposite order
-- Tx1: UPDATE orders SET ... WHERE id=1; UPDATE orders SET ... WHERE id=2;
-- Tx2: UPDATE orders SET ... WHERE id=2; UPDATE orders SET ... WHERE id=1;

-- Fix: always update in ascending ID order
UPDATE orders SET status='PROCESSING'
WHERE id IN (1, 2)
ORDER BY id; -- deterministic lock order

-- Application retry logic for deadlock
