// Spring Cloud AWS SQS consumer
@SqsListener(value = "order-processing-queue",
             deletionPolicy = SqsMessageDeletionPolicy.ON_SUCCESS)
void processOrder(String message, @Header("ApproximateReceiveCount") int retries) {
    try {
        Order order = objectMapper.readValue(message, Order.class);
        orderService.process(order);
        // Message auto-deleted on method return (ON_SUCCESS policy)
    } catch (Exception e) {
        // Throw to keep message visible → retry → DLQ after maxReceiveCount
        throw new RuntimeException("Processing failed", e);
    }
}

