// Redis distributed rate limiter with Spring Data Redis
@Component
public class RateLimiter {
    private final RedisTemplate<String, String> redis;

    public boolean isAllowed(String userId, int maxRequests, long windowSeconds) {
        String key = "rate:" + userId;
        long count = redis.opsForValue().increment(key);
        if (count == 1)
            redis.expire(key, Duration.ofSeconds(windowSeconds));
        return count <= maxRequests;
    }
}

// SNS → SQS fan-out pattern
// 1. Create SNS topic: arn:aws:sns:us-east-1:123:order-events
// 2. Subscribe two SQS queues:
//    - billing-queue (handles payment)
//    - inventory-queue (handles stock update)

// Publisher (Spring)
@Service
public class OrderService {
    @Autowired SnsTemplate snsTemplate;

    void placeOrder(Order o) {
        save(o);
        snsTemplate.sendNotification(
            "arn:aws:sns:...:order-events",
            toJson(o),          // both queues get this
            "ORDER_PLACED");
    }
}
